import java.util.*;

public class Solution {
    static class WaterRide {
        long start;
        long duration;

        WaterRide(long s, long d) {
            start = s;
            duration = d;
        }
    }

    static class LandRide {
        long start;
        long duration;

        LandRide(long s, long d) {
            start = s;
            duration = d;
        }
    }

    public static long solve(long[] landStartTime, long[] landDuration, long[] waterStartTime, long[] waterDuration) {
        int n = landStartTime.length;
        int m = waterStartTime.length;

        WaterRide[] waterRides = new WaterRide[m];
        for (int j = 0; j < m; j++) {
            waterRides[j] = new WaterRide(waterStartTime[j], waterDuration[j]);
        }
        Arrays.sort(waterRides, Comparator.comparingLong(a -> a.start));

        long[] waterPrefixMinD = new long[m];
        long[] waterSuffixMinSum = new long[m];

        if (m > 0) {
            waterPrefixMinD[0] = waterRides[0].duration;
            for (int i = 1; i < m; i++) {
                waterPrefixMinD[i] = Math.min(waterPrefixMinD[i - 1], waterRides[i].duration);
            }

            waterSuffixMinSum[m - 1] = waterRides[m - 1].start + waterRides[m - 1].duration;
            for (int i = m - 2; i >= 0; i--) {
                waterSuffixMinSum[i] = Math.min(waterSuffixMinSum[i + 1], waterRides[i].start + waterRides[i].duration);
            }
        }

        LandRide[] landRides = new LandRide[n];
        for (int i = 0; i < n; i++) {
            landRides[i] = new LandRide(landStartTime[i], landDuration[i]);
        }
        Arrays.sort(landRides, Comparator.comparingLong(a -> a.start));

        long[] landPrefixMinD = new long[n];
        long[] landSuffixMinSum = new long[n];

        if (n > 0) {
            landPrefixMinD[0] = landRides[0].duration;
            for (int i = 1; i < n; i++) {
                landPrefixMinD[i] = Math.min(landPrefixMinD[i - 1], landRides[i].duration);
            }

            landSuffixMinSum[n - 1] = landRides[n - 1].start + landRides[n - 1].duration;
            for (int i = n - 2; i >= 0; i--) {
                landSuffixMinSum[i] = Math.min(landSuffixMinSum[i + 1], landRides[i].start + landRides[i].duration);
            }
        }

        long ans = Long.MAX_VALUE;

        for (int i = 0; i < n; i++) {
            long landEnd = landStartTime[i] + landDuration[i];

            int low = 0;
            int high = m - 1;
            int waterIdx = -1;
            while (low <= high) {
                int mid = (low + high) >>> 1;
                if (waterRides[mid].start < landEnd) {
                    waterIdx = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }

            long candidate = Long.MAX_VALUE;
            if (waterIdx + 1 < m) {
                candidate = Math.min(candidate, waterSuffixMinSum[waterIdx + 1]);
            }
            if (waterIdx >= 0) {
                candidate = Math.min(candidate, landEnd + waterPrefixMinD[waterIdx]);
            }
            ans = Math.min(ans, candidate);
        }

        for (int j = 0; j < m; j++) {
            long waterEnd = waterStartTime[j] + waterDuration[j];

            int low = 0;
            int high = n - 1;
            int landIdx = -1;
            while (low <= high) {
                int mid = (low + high) >>> 1;
                if (landRides[mid].start < waterEnd) {
                    landIdx = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }

            long candidate = Long.MAX_VALUE;
            if (landIdx + 1 < n) {
                candidate = Math.min(candidate, landSuffixMinSum[landIdx + 1]);
            }
            if (landIdx >= 0) {
                candidate = Math.min(candidate, waterEnd + landPrefixMinD[landIdx]);
            }
            ans = Math.min(ans, candidate);
        }

        return ans;
    }
}
