import java.util.Arrays;

public class Solution {
    public static long solve(long[] landStartTime, long[] landDuration, long[] waterStartTime, long[] waterDuration) {
        int nLand = landStartTime.length;
        int nWater = waterStartTime.length;

        if (nWater == 0 || nLand == 0) {
            return Long.MAX_VALUE;
        }

        long[][] waterRides = new long[nWater][2];
        for (int i = 0; i < nWater; i++) {
            waterRides[i][0] = waterStartTime[i];
            waterRides[i][1] = waterDuration[i];
        }
        Arrays.sort(waterRides, (a, b) -> Long.compare(a[0], b[0]));

        long[] prefixMinWaterDur = new long[nWater];
        long[] suffixMinWaterSum = new long[nWater];

        prefixMinWaterDur[0] = waterRides[0][1];
        for (int i = 1; i < nWater; i++) {
            prefixMinWaterDur[i] = Math.min(prefixMinWaterDur[i - 1], waterRides[i][1]);
        }

        suffixMinWaterSum[nWater - 1] = waterRides[nWater - 1][0] + waterRides[nWater - 1][1];
        for (int i = nWater - 2; i >= 0; i--) {
            suffixMinWaterSum[i] = Math.min(suffixMinWaterSum[i + 1], waterRides[i][0] + waterRides[i][1]);
        }

        long[][] landRides = new long[nLand][2];
        for (int i = 0; i < nLand; i++) {
            landRides[i][0] = landStartTime[i];
            landRides[i][1] = landDuration[i];
        }
        Arrays.sort(landRides, (a, b) -> Long.compare(a[0], b[0]));

        long[] prefixMinLandDur = new long[nLand];
        long[] suffixMinLandSum = new long[nLand];

        prefixMinLandDur[0] = landRides[0][1];
        for (int i = 1; i < nLand; i++) {
            prefixMinLandDur[i] = Math.min(prefixMinLandDur[i - 1], landRides[i][1]);
        }

        suffixMinLandSum[nLand - 1] = landRides[nLand - 1][0] + landRides[nLand - 1][1];
        for (int i = nLand - 2; i >= 0; i--) {
            suffixMinLandSum[i] = Math.min(suffixMinLandSum[i + 1], landRides[i][0] + landRides[i][1]);
        }

        long ans = Long.MAX_VALUE;

        for (int i = 0; i < nLand; i++) {
            long T = landStartTime[i] + landDuration[i];
            int pos = lowerBound(waterRides, T);

            long candidate1 = Long.MAX_VALUE;
            if (pos < nWater) {
                candidate1 = suffixMinWaterSum[pos];
            }

            long candidate2 = Long.MAX_VALUE;
            if (pos > 0) {
                candidate2 = T + prefixMinWaterDur[pos - 1];
            }

            long candidate = Math.min(candidate1, candidate2);
            if (candidate < ans) {
                ans = candidate;
            }
        }

        for (int j = 0; j < nWater; j++) {
            long T = waterStartTime[j] + waterDuration[j];
            int pos = lowerBound(landRides, T);

            long candidate1 = Long.MAX_VALUE;
            if (pos < nLand) {
                candidate1 = suffixMinLandSum[pos];
            }

            long candidate2 = Long.MAX_VALUE;
            if (pos > 0) {
                candidate2 = T + prefixMinLandDur[pos - 1];
            }

            long candidate = Math.min(candidate1, candidate2);
            if (candidate < ans) {
                ans = candidate;
            }
        }

        return ans;
    }

    private static int lowerBound(long[][] arr, long key) {
        int low = 0;
        int high = arr.length - 1;
        while (low <= high) {
            int mid = (low + high) >>> 1;
            if (arr[mid][0] < key) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return low;
    }
}
